}

.fa-layers-counter, .fa-layers-text {
 display: inline-block;
 position: absolute;
 text-align: center;
}

.fa-layers-text {
 left: 50%;
 top: 50%;
 -webkit-transform: translate(-50%, -50%);
 transform: translate(-50%, -50%);
 -webkit-transform-origin: center center;
 transform-origin: center center;
}

