.ant-tag {
 box-sizing: border-box;
 margin: 0;
 padding: 0;
 color: rgba(0, 0, 0, 0.85);
 font-size: 14px;
 font-variant: tabular-nums;
 line-height: 1.5715;
 list-style: none;
 font-feature-settings: 'tnum', "tnum";
 display: inline-block;
 height: auto;
 margin-right: 8px;
 padding: 0 7px;
 font-size: 12px;
 line-height: 20px;
 white-space: nowrap;
 background: #fafafa;
 border: 1px solid #d9d9d9;
 border-radius: 2px;
 opacity: 1;
 transition: all 0.3s;
}
.ant-tag,
.ant-tag a,
.ant-tag a:hover {
 color: rgba(0, 0, 0, 0.85);
}
.ant-tag > a:first-child:last-child {
 display: inline-block;
 margin: 0 -8px;
 padding: 0 8px;
}
.ant-tag-close-icon {
 margin-left: 3px;
 color: rgba(0, 0, 0, 0.45);
 font-size: 10px;
 cursor: pointer;
